//! Transaction classifier for determining contract interactions via EVM simulation.
//!
//! # Overview
//!
//! This module classifies transactions by their contract interactions to determine
//! which sequencing rights bucket they belong to.

mod tests {
    use super::*;

    #[test]
    fn test_inspector_single_contract() {
        let mut inspector = ContractCallInspector::new();
        let contract = Address::repeat_byte(0x42);
        let selector = FixedBytes::from_slice(&[0x11, 0x22, 0x33, 0x44]);

        inspector.contract_calls.entry(contract).or_default().insert(selector);
        inspector.call_order.push((contract, selector));

        let (count, interaction) = inspector.classify();
        assert_eq!(count, 1);
        assert!(interaction.is_some());

        let interaction = interaction.unwrap();
        assert_eq!(interaction.contract, contract);
        assert!(interaction.selectors.contains(&selector));
    }
